import{_ as t,c as o,o as a,ah as s}from"./chunks/framework.RCw5T9E9.js";const g=JSON.parse('{"title":"Blacklist","description":"","frontmatter":{"title":"Blacklist"},"headers":[],"relativePath":"props/blacklist.md","filePath":"props/blacklist.md"}'),n={name:"props/blacklist.md"};function r(i,e,l,c,p,d){return a(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="component-blacklist-props" tabindex="-1">Component blacklist (Props) <a class="header-anchor" href="#component-blacklist-props" aria-label="Permalink to &quot;Component blacklist (Props)&quot;">​</a></h1><p>The <strong>Props</strong> <strong>blacklist</strong> is a set of <strong>Vue component names</strong> excluded from the inspector tree and table. Filtering runs <strong>before</strong> props collection, so hidden components are skipped during traversal.</p><p>Props overview: <a href="/qa-tools/docs/props/general.html">Overview</a>.</p><p>Do not confuse this with the <strong>site blacklist</strong> for overlay <strong>auto run</strong> (<strong>General / Auto Run</strong>): here only <strong>component names</strong> are filtered.</p><hr><h2 id="add-and-remove" tabindex="-1">Add and remove <a class="header-anchor" href="#add-and-remove" aria-label="Permalink to &quot;Add and remove&quot;">​</a></h2><ul><li><strong>Row context menu</strong> on <strong>Props</strong> — adds the current component name to the active block list.</li><li><strong>Options → Props → Component Blacklist</strong> — view rules, add lines, toggle state, delete.</li></ul><p>Duplicate names are usually not created.</p><hr><h2 id="active-vs-inactive" tabindex="-1">Active vs inactive <a class="header-anchor" href="#active-vs-inactive" aria-label="Permalink to &quot;Active vs inactive&quot;">​</a></h2><p>Rules have two states:</p><ul><li><strong>Blocked</strong> — applied; matching components are hidden.</li><li><strong>Off</strong> — stored but not filtering.</li></ul><p>Toggle without retyping. Deleting a row removes the rule entirely.</p><p>With no active rules, blacklist filtering is effectively off.</p><hr><h2 id="name-matching" tabindex="-1">Name matching <a class="header-anchor" href="#name-matching" aria-label="Permalink to &quot;Name matching&quot;">​</a></h2><p>Comparison uses the <strong>displayed component name</strong>.</p><ul><li>Without <strong><code>*</code></strong> or <strong><code>%</code></strong> — <strong>case-insensitive exact</strong> match.</li><li><strong><code>*</code></strong> and <strong><code>%</code></strong> act as wildcards for name fragments.</li></ul><p>Examples:</p><ul><li><code>MyButton</code> — only <strong>MyButton</strong>;</li><li><code>Base*</code> — names starting with <strong>Base</strong>;</li><li><code>*Modal*</code> — names containing <strong>Modal</strong>.</li></ul><p>Nameless components may show as <strong>Anonymous</strong> when that is what the tree uses.</p><hr><h2 id="intersections" tabindex="-1">Intersections <a class="header-anchor" href="#intersections" aria-label="Permalink to &quot;Intersections&quot;">​</a></h2><p>If several rules match, each rule’s <strong>active</strong> state applies.</p><p>Inactive rules do not act as exceptions — they are simply ignored until re-enabled.</p><p>Prefer toggling a broad pattern off temporarily instead of stacking near-duplicates.</p><hr><h2 id="when-it-applies" tabindex="-1">When it applies <a class="header-anchor" href="#when-it-applies" aria-label="Permalink to &quot;When it applies&quot;">​</a></h2><p>Rules run on every tree rebuild:</p><ul><li>manual <strong>Refresh</strong>;</li><li>automatic refresh;</li><li>reopening the tab.</li></ul><p>After <strong>Options</strong> edits the tree usually refreshes so the table reflects changes immediately.</p><p>While a rule is active, hidden components are not selectable in the table or card.</p><hr><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>Start from <strong>exact names</strong> via the row context menu.</li><li><strong>Wide patterns</strong> help repeated noise components but need care.</li><li><strong>Blacklist affects inspector display only</strong> — it does not change your Vue app.</li></ul><hr><h2 id="see-also" tabindex="-1">See also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See also&quot;">​</a></h2><ul><li><a href="/qa-tools/docs/props/general.html">Props overview</a></li><li><a href="/qa-tools/docs/props/inspect.html">Inspect</a></li><li><a href="/qa-tools/docs/options/customize.html">Customize</a></li></ul>',38)])])}const u=t(n,[["render",r]]);export{g as __pageData,u as default};
